package actor

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime/actor"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type EchoProxy struct {
	actor.UnimplementedEchoServer
	client actor.EchoClient
}

func init() {
	proxyutil.Register(&actor.Echo_ServiceDesc, NewEchoProxy)
}
func NewEchoProxy(cc grpc.ClientConnInterface) actor.EchoServer {
	return &EchoProxy{client: actor.NewEchoClient(cc)}
}
func (p *EchoProxy) Echo(ctx context.Context, in *runtime.Str) (*runtime.Str, error) {
	return proxyutil.ProxyMethod[runtime.Str, runtime.Str](p.client.Echo)(ctx, in)
}
